/* Safely encode an inline SVG string as a CSS data-URI. Hex colors like
   #193968 contain "#", which browsers treat as a URL fragment marker —
   left un-encoded it silently truncates the whole background-image at
   the first color, which is why an un-encoded version renders blank.
   encodeURIComponent handles this and every other reserved character. */
const svgToUrl = (svg) =>
  `url("data:image/svg+xml,${encodeURIComponent(svg)}")`;

