/* Deterministic seeded PRNG so the scattered layout is stable across
   re-renders (no flicker as component state changes). */
const seededRandom = (seed) => {
  let t = seed % 2147483647;
  if (t <= 0) t += 2147483646;
  return () => {
    t = (t * 16807) % 2147483647;
    return (t - 1) / 2147483646;
  };
};

/* Builds one tall SVG tile with the given icons scattered at varied
   position / rotation / scale / opacity, tinted to the theme color.
   The tile is then repeated vertically to cover a full-length page. */
const buildScatterBg = (iconKeys, color, seed) => {
  const rand = seededRandom(seed);
  const W = 900;
  const H = 1400;
  const count = 34;
  let groups = "";
  for (let i = 0; i < count; i++) {
    const key = iconKeys[i % iconKeys.length];
    const glyph = ICON_GLYPHS[key](color);
    const x = 10 + rand() * (W - 50);
    const y = 10 + rand() * (H - 50);
    const rot = Math.round(rand() * 360);
    const scale = (1.1 + rand() * 2.1).toFixed(2);
    const opacity = (0.05 + rand() * 0.06).toFixed(3);
    groups += `<g transform="translate(${x.toFixed(1)},${y.toFixed(
      1,
    )}) rotate(${rot}) scale(${scale})" opacity="${opacity}">${glyph}</g>`;
  }
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}">${groups}</svg>`;
  return svgToUrl(svg);
};

/* A handful of oversized icons placed at fixed, generous spots so the
   backdrop reads as a deliberate themed scene rather than confetti. */
const buildFeatureBg = (iconKeys, color, seed) => {
  const rand = seededRandom(seed);
  const W = 1200;
  const H = 1600;
  const spots = [
    { x: 90, y: 60 },
    { x: 950, y: 40 },
    { x: 60, y: 780 },
    { x: 980, y: 820 },
    { x: 520, y: 1200 },
    { x: 120, y: 1420 },
  ];
  let groups = "";
  spots.forEach((spot, i) => {
    const key = iconKeys[i % iconKeys.length];
    const glyph = ICON_GLYPHS[key](color);
    const rot = Math.round((rand() - 0.5) * 40);
    const scale = (4 + rand() * 3).toFixed(2);
    const opacity = (0.05 + rand() * 0.035).toFixed(3);
    groups += `<g transform="translate(${spot.x},${spot.y}) rotate(${rot}) scale(${scale})" opacity="${opacity}">${glyph}</g>`;
  });
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}">${groups}</svg>`;
  return svgToUrl(svg);
};

/* Single large corner motif dropped onto an individual section/card so
   each one reads as belonging to the active service at a glance. */
const buildMotif = (iconKey, color, size = 34) => {
  const glyph = ICON_GLYPHS[iconKey](color);
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${size}" height="${size}" viewBox="0 0 ${size} ${size}"><g transform="scale(${(
    size / 34
  ).toFixed(2)})">${glyph}</g></svg>`;
  return svgToUrl(svg);
};

/* Converts a hex color to an rgba() string at the given alpha, so every
   category theme below can be defined with just one hex color instead
   of hand-writing matching rgba() strings for glow/glowSoft/pageBg. */
const hexToRgba = (hex, alpha) => {
  const clean = hex.replace("#", "");
  const bigint = parseInt(clean, 16);
  const r = (bigint >> 16) & 255;
  const g = (bigint >> 8) & 255;
  const b = bigint & 255;
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

/* Builds one complete theme object (accent colors, page gradient,
   scattered backdrop, and per-section motifs) from a single accent
   color + icon set, so each category below only has to declare what
   makes it different. */
const makeTheme = ({ accent, accent2, icons, label, seed, motifIcons, image }) => ({
  accent,
  accent2,
  glow: hexToRgba(accent, 0.24),
  glowSoft: hexToRgba(accent, 0.13),
  pageBg: `linear-gradient(180deg, ${hexToRgba(accent, 0.16)} 0%, ${hexToRgba(
    accent,
    0.08,
  )} 45%, #F4F8FC 100%)`,
  label,
  image,
  scatterBg: buildScatterBg(icons, accent, seed),
  featureBg: buildFeatureBg(icons, accent, seed * 10 + 1),
  motif: {
    operator: buildMotif(motifIcons[0], accent, 220),
    bill: buildMotif(motifIcons[1], accent, 200),
    plan: buildMotif(motifIcons[2], accent, 210),
    pin: buildMotif(motifIcons[3], accent, 190),
  },
});

