/* ---------- per-service theme: accent pair, a full-page scattered
   icon backdrop, and per-section corner motifs so operator select /
   bill details / plan popup / TPIN dialog each feel purpose-built for
   the active service ---------- */
const getServiceTheme = (serviceNameRaw, isMobileRecharge, isDth) => {
  if (isMobileRecharge) {
    return makeTheme({
      accent: NAVY,
      accent2: NAVY_SOFT,
      icons: ["phone", "signalBars", "wifi", "sim", "rupee", "tower"],
      motifIcons: ["sim", "signalBars", "wifi", "phone"],
      label: "Mobile Recharge",
      seed: 11,
      image: mobilerecharge,
    });
  }
  if (isDth) {
    return makeTheme({
      accent: NAVY,
      accent2: NAVY_SOFT,
      icons: ["dish", "tv", "remote", "antenna", "rupee", "channelGrid"],
      motifIcons: ["dish", "tv", "remote", "antenna"],
      label: "DTH Recharge",
      seed: 22,
      image: dth,
    });
  }

  const name = (serviceNameRaw || "").toLowerCase();
  const category = CATEGORY_THEMES.find((cat) => cat.test.test(name));
  if (category) {
    // seed derived from a simple hash of the category label so each
    // category keeps a stable (but distinct) scatter layout
    const seed = category.label
      .split("")
      .reduce((acc, ch) => acc + ch.charCodeAt(0), 0);
    return makeTheme({
      // same navy accent pair as Mobile Recharge for every category —
      // color no longer varies by service, only the icon set/image does
      accent: NAVY,
      accent2: NAVY_SOFT,
      icons: category.icons,
      motifIcons: category.motifIcons,
      label: category.label,
      seed,
      image: category.image,
    });
  }

  // fallback generic theme for any category not explicitly mapped above
  return makeTheme({
    accent: NAVY,
    accent2: NAVY_SOFT,
    icons: ["receipt", "coin", "calculator", "folder", "shieldCheck", "wallet", "bank"],
    motifIcons: ["folder", "receipt", "tag", "shieldCheck"],
    label: "Bill Payment",
    seed: 33,
    image: billpayment,
  });
};

